import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, BusinessInfo, ImpactLevel } from "../types";

// Helper to ensure API key is present
const getApiKey = (): string => {
  const key = process.env.API_KEY;
  if (!key) {
    throw new Error("API Key not found. Please set REACT_APP_GEMINI_API_KEY.");
  }
  return key;
};

export const analyzeBusinessVisibility = async (business: BusinessInfo): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });

  const prompt = `
    Analyze the "LLM Visibility" (or Generative Engine Optimization - GEO) for the following local business.

    Business Name: ${business.name}
    Location: ${business.location}
    Category: ${business.category}
    ${business.website ? `Website: ${business.website}` : ''}

    Your goal is to simulate how a large language model or AI search engine (like Gemini, ChatGPT, Perplexity) perceives this business.

    1. Use Google Search to find real-time information, reviews, and citations for this business and its top local competitors.
    2. Simulate 3 distinct user queries a potential customer would ask (e.g., "best [category] in [location]", "cheap [category] near me", "[category] with good reviews").
    3. Generate a realistic AI response for those queries based on the search results you found. Does the business appear?
    4. Rate the business on Authority, Consistency (NAP), Sentiment, Relevance, and Citations (0-100).
    5. Identify 3 major competitors ranking for similar terms.
    6. Provide actionable recommendations to improve visibility in AI answers.

    Return the result strictly in JSON format.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            overallScore: { type: Type.NUMBER, description: "Overall LLM visibility score 0-100" },
            summary: { type: Type.STRING, description: "A brief executive summary of the business's AI presence." },
            attributes: {
              type: Type.OBJECT,
              properties: {
                authority: { type: Type.NUMBER },
                consistency: { type: Type.NUMBER },
                sentiment: { type: Type.NUMBER },
                relevance: { type: Type.NUMBER },
                citations: { type: Type.NUMBER },
              },
              required: ["authority", "consistency", "sentiment", "relevance", "citations"]
            },
            simulations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  query: { type: Type.STRING },
                  aiResponse: { type: Type.STRING, description: "A summarized simulated response an AI might give." },
                  rank: { type: Type.STRING, enum: ["Top Recommendation", "Mentioned", "Not Found"] }
                }
              }
            },
            competitors: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  strengths: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
              }
            },
            recommendations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  impact: { type: Type.STRING, enum: [ImpactLevel.HIGH, ImpactLevel.MEDIUM, ImpactLevel.LOW] },
                  actionItem: { type: Type.STRING }
                }
              }
            }
          },
          required: ["overallScore", "summary", "attributes", "simulations", "competitors", "recommendations"]
        }
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response from AI");
    }

    const data = JSON.parse(text) as AnalysisResult;
    return data;

  } catch (error) {
    console.error("Error analyzing business:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { BusinessInfo } from '../types';
import { SparklesIcon, MapPinIcon, GlobeIcon, SearchIcon } from './Icons';

interface Props {
  onSubmit: (info: BusinessInfo) => void;
  isLoading: boolean;
}

const BusinessForm: React.FC<Props> = ({ onSubmit, isLoading }) => {
  const [info, setInfo] = useState<BusinessInfo>({
    name: '',
    location: '',
    category: '',
    website: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (info.name && info.location && info.category) {
      onSubmit(info);
    }
  };

  return (
    <div className="w-full max-w-2xl mx-auto">
      <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-100">
        <div className="p-8 bg-gradient-to-r from-indigo-600 to-violet-600 text-white">
          <h2 className="text-3xl font-bold mb-2 flex items-center gap-3">
            <SparklesIcon className="w-8 h-8 text-yellow-300" />
            Analyze Your AI Visibility
          </h2>
          <p className="text-indigo-100 text-lg">
            See how your local business appears in AI search results like Gemini and ChatGPT.
          </p>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="block text-sm font-medium text-slate-700">Business Name *</label>
              <div className="relative">
                <input
                  type="text"
                  required
                  placeholder="e.g. Joe's Coffee Spot"
                  className="w-full pl-4 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none"
                  value={info.name}
                  onChange={(e) => setInfo(prev => ({ ...prev, name: e.target.value }))}
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="block text-sm font-medium text-slate-700">Category *</label>
              <div className="relative">
                <div className="absolute left-3 top-3.5 text-slate-400">
                  <SearchIcon className="w-5 h-5" />
                </div>
                <input
                  type="text"
                  required
                  placeholder="e.g. Coffee Shop, Plumber"
                  className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none"
                  value={info.category}
                  onChange={(e) => setInfo(prev => ({ ...prev, category: e.target.value }))}
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="block text-sm font-medium text-slate-700">Location (City/Area) *</label>
              <div className="relative">
                <div className="absolute left-3 top-3.5 text-slate-400">
                  <MapPinIcon className="w-5 h-5" />
                </div>
                <input
                  type="text"
                  required
                  placeholder="e.g. Austin, TX"
                  className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none"
                  value={info.location}
                  onChange={(e) => setInfo(prev => ({ ...prev, location: e.target.value }))}
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="block text-sm font-medium text-slate-700">Website (Optional)</label>
              <div className="relative">
                <div className="absolute left-3 top-3.5 text-slate-400">
                  <GlobeIcon className="w-5 h-5" />
                </div>
                <input
                  type="url"
                  placeholder="https://..."
                  className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none"
                  value={info.website}
                  onChange={(e) => setInfo(prev => ({ ...prev, website: e.target.value }))}
                />
              </div>
            </div>
          </div>

          <button
            type="submit"
            disabled={isLoading}
            className={`w-full py-4 px-6 rounded-xl font-bold text-lg text-white shadow-lg transition-all transform hover:-translate-y-0.5 active:translate-y-0
              ${isLoading 
                ? 'bg-slate-400 cursor-not-allowed' 
                : 'bg-indigo-600 hover:bg-indigo-700 hover:shadow-indigo-200'
              }`}
          >
            {isLoading ? (
              <span className="flex items-center justify-center gap-2">
                <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                Analyzing Web Presence...
              </span>
            ) : (
              'Run Visibility Audit'
            )}
          </button>
        </form>
      </div>
    </div>
  );
};

export default BusinessForm;

import React from 'react';
import { AnalysisResult, ImpactLevel } from '../types';
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, Cell } from 'recharts';
import { AlertCircleIcon, CheckCircleIcon, TrendingUpIcon, RefreshCwIcon } from './Icons';

interface Props {
  data: AnalysisResult;
  businessName: string;
  onReset: () => void;
}

const Dashboard: React.FC<Props> = ({ data, businessName, onReset }) => {

  const attributeData = [
    { subject: 'Authority', A: data.attributes.authority, fullMark: 100 },
    { subject: 'Consistency', A: data.attributes.consistency, fullMark: 100 },
    { subject: 'Sentiment', A: data.attributes.sentiment, fullMark: 100 },
    { subject: 'Relevance', A: data.attributes.relevance, fullMark: 100 },
    { subject: 'Citations', A: data.attributes.citations, fullMark: 100 },
  ];

  const getScoreColor = (score: number) => {
    if (score >= 80) return 'text-green-600';
    if (score >= 60) return 'text-yellow-600';
    return 'text-red-600';
  };

  const getImpactColor = (impact: ImpactLevel) => {
    switch (impact) {
      case ImpactLevel.HIGH: return 'bg-red-100 text-red-800 border-red-200';
      case ImpactLevel.MEDIUM: return 'bg-yellow-100 text-yellow-800 border-yellow-200';
      case ImpactLevel.LOW: return 'bg-blue-100 text-blue-800 border-blue-200';
    }
  };

  return (
    <div className="space-y-8 animate-fade-in">
      {/* Header Actions */}
      <div className="flex justify-between items-center mb-6">
        <div>
           <h2 className="text-2xl font-bold text-slate-800">Audit Results for <span className="text-indigo-600">{businessName}</span></h2>
           <p className="text-slate-500 text-sm mt-1">Generated by LocalPulse AI</p>
        </div>
        <button 
          onClick={onReset}
          className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-slate-600 bg-white border border-slate-300 rounded-lg hover:bg-slate-50 transition-colors"
        >
          <RefreshCwIcon className="w-4 h-4" />
          New Audit
        </button>
      </div>

      {/* Top Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Overall Score */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 flex flex-col items-center justify-center relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 to-purple-500"></div>
            <h3 className="text-slate-500 font-medium text-sm uppercase tracking-wider mb-2">Visibility Score</h3>
            <div className={`text-6xl font-bold ${getScoreColor(data.overallScore)}`}>
                {data.overallScore}
            </div>
            <p className="text-slate-400 text-sm mt-2">out of 100</p>
        </div>

        {/* Summary */}
        <div className="md:col-span-2 bg-white rounded-2xl shadow-sm border border-slate-200 p-6 relative">
            <div className="absolute top-0 left-0 w-full h-2 bg-indigo-500"></div>
            <h3 className="text-slate-800 font-bold text-lg mb-3">AI Perception Summary</h3>
            <p className="text-slate-600 leading-relaxed">
                {data.summary}
            </p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

        {/* Attribute Radar Chart */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
                <TrendingUpIcon className="w-5 h-5 text-indigo-500" />
                Visibility Attributes
            </h3>
            <div className="h-[300px] w-full">
                <ResponsiveContainer width="100%" height="100%">
                    <RadarChart cx="50%" cy="50%" outerRadius="80%" data={attributeData}>
                        <PolarGrid stroke="#e2e8f0" />
                        <PolarAngleAxis dataKey="subject" tick={{ fill: '#64748b', fontSize: 12 }} />
                        <PolarRadiusAxis angle={30} domain={[0, 100]} tick={false} axisLine={false} />
                        <Radar
                            name="Your Business"
                            dataKey="A"
                            stroke="#6366f1"
                            strokeWidth={3}
                            fill="#818cf8"
                            fillOpacity={0.5}
                        />
                        <Tooltip 
                             contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                        />
                    </RadarChart>
                </ResponsiveContainer>
            </div>
        </div>

        {/* Competitor Analysis */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
            <h3 className="text-lg font-bold text-slate-800 mb-6">Top Competitors in AI Results</h3>
            <div className="space-y-4">
                {data.competitors.map((comp, idx) => (
                    <div key={idx} className="p-4 bg-slate-50 rounded-xl border border-slate-100">
                        <div className="flex justify-between items-start mb-2">
                            <h4 className="font-bold text-slate-700">{comp.name}</h4>
                            <span className="text-xs font-semibold bg-slate-200 text-slate-600 px-2 py-1 rounded">Ranked</span>
                        </div>
                        <div className="flex flex-wrap gap-2">
                            {comp.strengths.map((s, sIdx) => (
                                <span key={sIdx} className="text-xs text-indigo-600 bg-indigo-50 px-2 py-1 rounded-full border border-indigo-100">
                                    {s}
                                </span>
                            ))}
                        </div>
                    </div>
                ))}
                {data.competitors.length === 0 && (
                    <p className="text-slate-400 italic text-center py-8">No specific competitors identified in this scan.</p>
                )}
            </div>
        </div>
      </div>

      {/* Simulation Results */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
          <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
              <CheckCircleIcon className="w-5 h-5 text-green-500" />
              Simulated AI Responses
          </h3>
          <div className="space-y-4">
              {data.simulations.map((sim, idx) => (
                  <div key={idx} className="border border-slate-200 rounded-xl overflow-hidden">
                      <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex justify-between items-center">
                          <p className="font-medium text-slate-700 text-sm">User Query: "{sim.query}"</p>
                          <span className={`text-xs font-bold px-2 py-1 rounded uppercase tracking-wide
                              ${sim.rank === 'Top Recommendation' ? 'bg-green-100 text-green-700' : 
                                sim.rank === 'Mentioned' ? 'bg-yellow-100 text-yellow-700' : 'bg-red-100 text-red-700'}`}>
                              {sim.rank}
                          </span>
                      </div>
                      <div className="p-4 bg-white">
                          <p className="text-slate-600 text-sm italic">
                              AI: "{sim.aiResponse}"
                          </p>
                      </div>
                  </div>
              ))}
          </div>
      </div>

      {/* Recommendations */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
        <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
            <AlertCircleIcon className="w-5 h-5 text-orange-500" />
            Optimization Action Plan
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {data.recommendations.map((rec, idx) => (
                <div key={idx} className="p-5 border border-slate-100 rounded-xl shadow-sm hover:shadow-md transition-shadow bg-gradient-to-br from-white to-slate-50">
                    <div className="flex justify-between items-start mb-3">
                        <h4 className="font-bold text-slate-800">{rec.title}</h4>
                        <span className={`text-xs px-2 py-1 rounded border ${getImpactColor(rec.impact)}`}>
                            {rec.impact} Impact
                        </span>
                    </div>
                    <p className="text-sm text-slate-600 mb-4 h-10 line-clamp-2">{rec.description}</p>
                    <div className="mt-2 pt-3 border-t border-slate-100">
                        <p className="text-xs font-semibold text-indigo-600 uppercase tracking-wide mb-1">Action Item</p>
                        <p className="text-sm text-slate-800">{rec.actionItem}</p>
                    </div>
                </div>
            ))}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { AnalysisResult, AnalysisState, BusinessInfo } from './types';
import BusinessForm from './components/BusinessForm';
import Dashboard from './components/Dashboard';
import { analyzeBusinessVisibility } from './services/geminiService';
import { SparklesIcon } from './components/Icons';

const App: React.FC = () => {
  const [state, setState] = useState<AnalysisState>({
    loading: false,
    error: null,
    result: null,
  });

  const [businessName, setBusinessName] = useState<string>('');

  const handleAnalysis = async (info: BusinessInfo) => {
    setState({ loading: true, error: null, result: null });
    setBusinessName(info.name);

    try {
      const result = await analyzeBusinessVisibility(info);
      setState({ loading: false, error: null, result });
    } catch (err: any) {
      // Very basic error handling for demo
      const errorMessage = err?.message || "An unexpected error occurred. Please try again.";
      setState({ loading: false, error: errorMessage, result: null });
    }
  };

  const handleReset = () => {
    setState({ loading: false, error: null, result: null });
    setBusinessName('');
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Navigation */}
      <nav className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16">
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center">
                <SparklesIcon className="w-5 h-5 text-white" />
