import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, BusinessInfo, ImpactLevel } from "../types";

const getApiKey = (): string => {
  const key = process.env.API_KEY;
  if (!key) {
    throw new Error("API Key not found. Please set REACT_APP_GEMINI_API_KEY.");
  }
  return key;
};

export const analyzeBusinessVisibility = async (business: BusinessInfo): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });

  const prompt = `
    Analyze the "LLM Visibility" (GEO - Generative Engine Optimization) for the following local business.

    Business Name: ${business.name}
    Location: ${business.location}
    Category: ${business.category}
    ${business.website ? `Website: ${business.website}` : ''}
    ${business.keywords ? `Target Keywords to Rank For: ${business.keywords}` : ''}

    Task: Simulate how a modern AI (Gemini, ChatGPT, Perplexity) perceives this business.

    1.  **Research**: Use Google Search to find real-time info, reviews, citations, and competitor rankings.
    2.  **Standard Simulation**: Simulate 3 general user queries.
    3.  **Persona Analysis**: Create 3 distinct customer personas (e.g., "The Budget Conscious", "The Expert/Enthusiast", "The Urgent Need") and simulate their specific queries.
    4.  **Gap Analysis**: Identify exactly what data is missing from the web that prevents AI from recommending this business (e.g., "No pricing menu found", "Hours inconsistent").
    5.  **Platform Score**: Estimate visibility on Chat (Conversational), Voice (Brief answers), and Search (List based).
    6.  **Scoring**: Rate Authority, Consistency, Sentiment, Relevance, Citations (0-100).

    Return strict JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            overallScore: { type: Type.NUMBER, description: "0-100" },
            summary: { type: Type.STRING },
            attributes: {
              type: Type.OBJECT,
              properties: {
                authority: { type: Type.NUMBER },
                consistency: { type: Type.NUMBER },
                sentiment: { type: Type.NUMBER },
                relevance: { type: Type.NUMBER },
                citations: { type: Type.NUMBER },
              },
              required: ["authority", "consistency", "sentiment", "relevance", "citations"]
            },
            simulations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  query: { type: Type.STRING },
                  aiResponse: { type: Type.STRING },
                  rank: { type: Type.STRING, enum: ["Top Recommendation", "Mentioned", "Not Found"] }
                }
              }
            },
            personas: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  personaName: { type: Type.STRING },
                  userIntent: { type: Type.STRING },
                  simulatedQuery: { type: Type.STRING },
                  aiResponseSummary: { type: Type.STRING },
                  brandMentioned: { type: Type.BOOLEAN }
                }
              }
            },
            contentGaps: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  missingElement: { type: Type.STRING },
                  importance: { type: Type.STRING, enum: [ImpactLevel.HIGH, ImpactLevel.MEDIUM, ImpactLevel.LOW] },
                  fix: { type: Type.STRING }
                }
              }
            },
            platformPerformance: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  platform: { type: Type.STRING, enum: ["Chat Interfaces", "Voice Search", "Traditional Search"] },
                  score: { type: Type.NUMBER },
                  status: { type: Type.STRING, enum: ["Optimized", "Needs Work", "Invisible"] }
                }
              }
            },
            competitors: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  strengths: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
              }
            },
            recommendations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  impact: { type: Type.STRING, enum: [ImpactLevel.HIGH, ImpactLevel.MEDIUM, ImpactLevel.LOW] },
                  actionItem: { type: Type.STRING }
                }
              }
            }
          },
          required: ["overallScore", "summary", "attributes", "simulations", "personas", "contentGaps", "platformPerformance", "competitors", "recommendations"]
        }
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response from AI");
    }

    const data = JSON.parse(text) as AnalysisResult;
    return data;

  } catch (error) {
    console.error("Error analyzing business:", error);
    throw error;
  }
};

