export interface AnalysisResult {
  overallScore: number;
  summary: string;
  attributes: {
    authority: number;
    consistency: number;
    sentiment: number;
    relevance: number;
    citations: number;
  };
  simulations: Simulation[];
  personas: PersonaSimulation[];
  contentGaps: ContentGap[];
  platformPerformance: PlatformPerformance[];

  // New Fields
  llmPerformance: LLMPerformance[];
  citationOpportunities: CitationOpportunity[];
  localCompetitors: LocalCompetitorLocation[];

  competitors: Competitor[];
  recommendations: Recommendation[];
}

export interface AnalysisState {
  loading: boolean;
  error: string | null;
  result: AnalysisResult | null;
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, BusinessInfo, ImpactLevel } from "../types";

const getApiKey = (): string => {
  const key = process.env.API_KEY;
  if (!key) {
    throw new Error("API Key not found. Please set REACT_APP_GEMINI_API_KEY.");
  }
  return key;
};

export const analyzeBusinessVisibility = async (business: BusinessInfo): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });

  const prompt = `
    Analyze the "LLM Visibility" (GEO - Generative Engine Optimization) for:

    Business: ${business.name}
    Location: ${business.location}
    Category: ${business.category}
    ${business.website ? `Website: ${business.website}` : ''}
    ${business.keywords ? `Keywords: ${business.keywords}` : ''}

    Task: Simulate an advanced SEO audit for AI engines.

    1.  **Research**: Use Google Search to find real info, reviews, citations, and competitors.
    2.  **LLM Ranking**: Simulate how this business appears specifically in ChatGPT, Gemini, and Perplexity for local queries.
    3.  **Local Map Simulation**: Identify 5 key competitors. Estimate their relative location to the business (e.g., North, South-East) and assign relative X/Y coordinates (range -10 to 10) where the business is (0,0). X is East/West, Y is North/South. Assign a simulated "Rank" (1-5).
    4.  **Citations**: Recommend 5 specific high-impact websites (e.g., Reddit, Yelp, Doctolib, TripAdvisor, local directories) where this business MUST be listed to improve AI confidence.
    5.  **Standard Analysis**: Personas, Content Gaps, Attributes.

    Return strict JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            overallScore: { type: Type.NUMBER },
            summary: { type: Type.STRING },
            attributes: {
              type: Type.OBJECT,
              properties: {
                authority: { type: Type.NUMBER },
                consistency: { type: Type.NUMBER },
                sentiment: { type: Type.NUMBER },
                relevance: { type: Type.NUMBER },
                citations: { type: Type.NUMBER },
              },
              required: ["authority", "consistency", "sentiment", "relevance", "citations"]
            },
            simulations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  query: { type: Type.STRING },
                  aiResponse: { type: Type.STRING },
                  rank: { type: Type.STRING, enum: ["Top Recommendation", "Mentioned", "Not Found"] }
                }
              }
            },
            personas: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  personaName: { type: Type.STRING },
                  userIntent: { type: Type.STRING },
                  simulatedQuery: { type: Type.STRING },
                  aiResponseSummary: { type: Type.STRING },
                  brandMentioned: { type: Type.BOOLEAN }
                }
              }
            },
            contentGaps: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  missingElement: { type: Type.STRING },
                  importance: { type: Type.STRING, enum: [ImpactLevel.HIGH, ImpactLevel.MEDIUM, ImpactLevel.LOW] },
                  fix: { type: Type.STRING }
                }
              }
            },
            platformPerformance: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  platform: { type: Type.STRING, enum: ["Chat Interfaces", "Voice Search", "Traditional Search"] },
                  score: { type: Type.NUMBER },
                  status: { type: Type.STRING, enum: ["Optimized", "Needs Work", "Invisible"] }
                }
              }
            },
            llmPerformance: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  model: { type: Type.STRING, enum: ["ChatGPT", "Gemini", "Perplexity"] },
                  status: { type: Type.STRING, enum: ["Top Choice", "Option", "Hidden"] },
                  details: { type: Type.STRING },
                  score: { type: Type.NUMBER }
                }
              }
            },
            localCompetitors: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  rank: { type: Type.NUMBER },
                  distance: { type: Type.STRING },
                  x: { type: Type.NUMBER },
                  y: { type: Type.NUMBER }
                }
              }
            },
            citationOpportunities: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  siteName: { type: Type.STRING },
                  domain: { type: Type.STRING },
                  type: { type: Type.STRING, enum: ["Directory", "Social", "Forum", "Health/Niche"] },
                  priority: { type: Type.STRING, enum: [ImpactLevel.HIGH, ImpactLevel.MEDIUM, ImpactLevel.LOW] },
                  reason: { type: Type.STRING }
                }
              }
            },
            competitors: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  strengths: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
              }
            },
            recommendations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  impact: { type: Type.STRING, enum: [ImpactLevel.HIGH, ImpactLevel.MEDIUM, ImpactLevel.LOW] },
                  actionItem: { type: Type.STRING }
                }
              }
            }
          },
          required: ["overallScore", "summary", "attributes", "simulations", "personas", "contentGaps", "platformPerformance", "llmPerformance", "localCompetitors", "citationOpportunities", "competitors", "recommendations"]
        }
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response from AI");
    }

    const data = JSON.parse(text) as AnalysisResult;
    return data;

  } catch (error) {
    console.error("Error analyzing business:", error);
    throw error;
  }
};

