            className={`${activeTab === 'citations' ? 'border-indigo-500 text-indigo-600' : 'border-transparent text-slate-500 hover:text-slate-700 hover:border-slate-300'} whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm transition-colors`}
          >
            Citation Builder
          </button>
        </nav>
      </div>

      <div className="min-h-[500px] mt-6">
        {activeTab === 'overview' && renderOverview()}
        {activeTab === 'llms' && renderLLMs()}
        {activeTab === 'map' && renderMap()}
        {activeTab === 'citations' && renderCitations()}
      </div>

    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { AnalysisResult, AnalysisState, BusinessInfo } from './types';
import BusinessForm from './components/BusinessForm';
import Dashboard from './components/Dashboard';
import { analyzeBusinessVisibility } from './services/geminiService';
import { SparklesIcon } from './components/Icons';

const App: React.FC = () => {
  const [state, setState] = useState<AnalysisState>({
    loading: false,
    error: null,
    result: null,
  });

  const [businessName, setBusinessName] = useState<string>('');

  const handleAnalysis = async (info: BusinessInfo) => {
    setState({ loading: true, error: null, result: null });
    setBusinessName(info.name);

    try {
      const result = await analyzeBusinessVisibility(info);
      setState({ loading: false, error: null, result });
    } catch (err: any) {
      const errorMessage = err?.message || "An unexpected error occurred. Please try again.";
      setState({ loading: false, error: errorMessage, result: null });
    }
  };

  const handleReset = () => {
    setState({ loading: false, error: null, result: null });
    setBusinessName('');
  };

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col text-slate-100">
      {/* Background Gradient Mesh Effect */}
      <div className="fixed inset-0 z-0 pointer-events-none opacity-20" style={{
        backgroundImage: 'radial-gradient(circle at 50% 0%, #4338ca 0%, transparent 40%), radial-gradient(circle at 0% 100%, #be185d 0%, transparent 30%)'
      }}></div>

      {/* Navigation */}
      <nav className="bg-slate-900/80 backdrop-blur-md border-b border-slate-800 sticky top-0 z-50">
