              <span className="font-bold text-xl tracking-tight text-white">LocalPulse<span className="text-indigo-400">AI</span></span>
            </div>
            <div className="flex items-center">
               <span className="text-xs font-semibold bg-slate-800 text-indigo-300 border border-slate-700 px-3 py-1 rounded-full uppercase tracking-wider">Beta Release</span>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="flex-grow py-12 px-4 sm:px-6 lg:px-8 relative z-10">
        <div className="max-w-7xl mx-auto">

          {/* Error Message */}
          {state.error && (
