        </nav>
      </div>

      {/* Content Area */}
      <div className="mt-8 min-h-[500px]">
        {activeTab === 'overview' && renderOverview()}
        {activeTab === 'deepdive' && renderDeepDive()}
        {activeTab === 'llms' && renderLLMs()}
        {activeTab === 'map' && renderMap()}
        {activeTab === 'citations' && renderCitations()}
      </div>

    </div>
  );
};

