                                 <span className="text-xs font-mono text-zinc-500">{entity.frequency}</span>
                                 <span className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded border
                                     ${entity.impact === 'Critical' ? 'bg-rose-500/10 border-rose-500/30 text-rose-400' : 
                                       entity.impact === 'Moderate' ? 'bg-amber-500/10 border-amber-500/30 text-amber-400' : 
                                       'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>
                                     {entity.impact} Impact
                                 </span>
                             </div>
                         </div>
                    ))}
                    {data.sentimentAudit?.negativeEntities.length === 0 && (
                        <div className="flex items-center gap-2 p-3 bg-emerald-500/5 border border-emerald-500/20 rounded">
                            <CheckCircleIcon className="w-4 h-4 text-emerald-500" />
                            <span className="text-sm text-emerald-400">Clean bill of health. No recurring negative entities found in simulated training data.</span>
                        </div>
                    )}
                </div>
            </div>
        </div>
     )
  }

  return (
    <div className="space-y-8 pb-12">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 pt-4">
        <div>
           <h2 className="text-3xl font-bold text-white tracking-tight">{businessName}</h2>
           <div className="flex items-center gap-2 mt-2">
              <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_8px_#10b981]"></span>
              <p className="text-zinc-500 text-xs font-mono uppercase tracking-wide">Analysis Complete</p>
           </div>
        </div>
        <button 
          onClick={onReset}
          className="flex items-center gap-2 px-5 py-2.5 text-xs font-bold tracking-wide text-zinc-900 bg-white rounded hover:bg-zinc-200 transition-colors shadow-[0_0_15px_rgba(255,255,255,0.1)]"
        >
          <RefreshCwIcon className="w-3 h-3" />
          NEW AUDIT
        </button>
      </div>

      {/* Tabs */}
      <div className="border-b border-zinc-800">
        <nav className="-mb-px flex space-x-8 overflow-x-auto" aria-label="Tabs">
          {[
            { id: 'overview', label: 'Overview' },
            { id: 'deepdive', label: 'Deep Dive', special: true },
            { id: 'llms', label: 'Models' },
            { id: 'map', label: 'Map' },
            { id: 'citations', label: 'Citations' }
          ].map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`${
                activeTab === tab.id
                  ? 'border-indigo-500 text-white'
                  : 'border-transparent text-zinc-500 hover:text-zinc-300 hover:border-zinc-700'
              } whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm transition-colors uppercase tracking-wider flex items-center gap-2`}
            >
              {tab.label}
              {tab.special && <span className="w-1.5 h-1.5 rounded-full bg-amber-500 animate-pulse"></span>}
            </button>
          ))}
        </nav>
      </div>

      {/* Content Area */}
      <div className="mt-8 min-h-[500px]">
        {activeTab === 'overview' && renderOverview()}
        {activeTab === 'deepdive' && renderDeepDive()}
        {activeTab === 'llms' && renderLLMs()}
        {activeTab === 'map' && renderMap()}
        {activeTab === 'citations' && renderCitations()}
      </div>

    </div>
  );
};

export default Dashboard;

export interface BusinessInfo {
  name: string;
  location: string;
  category: string;
  website?: string;
  keywords?: string;
}

export interface Simulation {
  query: string;
  aiResponse: string;
  rank: 'Top Recommendation' | 'Mentioned' | 'Not Found';
}

export enum ImpactLevel {
  HIGH = 'High',
  MEDIUM = 'Medium',
  LOW = 'Low'
}

export interface Recommendation {
  title: string;
  description: string;
  impact: ImpactLevel;
  actionItem: string;
}

export interface Competitor {
  name: string;
  strengths: string[];
}

export interface PersonaSimulation {
  personaName: string;
  userIntent: string;
  simulatedQuery: string;
  aiResponseSummary: string;
  brandMentioned: boolean;
}

export interface ContentGap {
  missingElement: string;
  importance: ImpactLevel;
  fix: string;
}

export interface PlatformPerformance {
  platform: 'Chat Interfaces' | 'Voice Search' | 'Traditional Search';
  score: number;
  status: 'Optimized' | 'Needs Work' | 'Invisible';
}

// New Types
export interface LLMPerformance {
  model: 'ChatGPT' | 'Gemini' | 'Perplexity';
  status: 'Top Choice' | 'Option' | 'Hidden';
  details: string;
  score: number; // 0-100 visibility score
}

export interface CitationOpportunity {
  siteName: string;
  domain: string;
  type: 'Directory' | 'Social' | 'Forum' | 'Health/Niche';
  priority: ImpactLevel;
  reason: string;
}

export interface LocalCompetitorLocation {
  name: string;
  rank: number;
  distance: string; // e.g., "0.5 miles"
  x: number; // Relative coordinate for map visualization (-10 to 10)
  y: number; // Relative coordinate for map visualization (-10 to 10)
}

// Feature 3: Keyword Heist
export interface KeywordGap {
  term: string;
  owner: 'Competitor' | 'You' | 'Shared';
  searchVolume: 'High' | 'Medium' | 'Low';
  opportunityScore: number; // 0-100
}

// Feature 5: Sentiment Audit
export interface NegativeEntity {
  term: string; // e.g. "Rude", "Slow", "Expensive"
  frequency: string; // e.g. "14% of reviews"
  impact: 'Critical' | 'Moderate' | 'Low';
}

// New Rich Attribute Interface for clearer KPIs
export interface AttributeDetail {
  score: number;
  label: string; // e.g. "Excellent", "Needs Work"
  explanation: string; // Simple English explanation
  action: string; // Immediate next step
}

export interface AnalysisResult {
  overallScore: number;
  summary: string;
  attributes: {
    authority: AttributeDetail;
    consistency: AttributeDetail;
    sentiment: AttributeDetail;
    relevance: AttributeDetail;
    citations: AttributeDetail;
  };
  simulations: Simulation[];
  personas: PersonaSimulation[];
  contentGaps: ContentGap[];
  platformPerformance: PlatformPerformance[];

  // New Fields
  llmPerformance: LLMPerformance[];
  citationOpportunities: CitationOpportunity[];
  localCompetitors: LocalCompetitorLocation[];

  // High Value Features
  keywordHeist: KeywordGap[];
  sentimentAudit: {
    toxicityScore: number; // 0-100 (0 is clean, 100 is toxic)
    negativeEntities: NegativeEntity[];
    summary: string;
  };

  competitors: Competitor[];
  recommendations: Recommendation[];
}

export interface AnalysisState {
  loading: boolean;
  error: string | null;
  result: AnalysisResult | null;
}

