                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                term: { type: Type.STRING },
                                frequency: { type: Type.STRING },
                                impact: { type: Type.STRING, enum: ['Critical', 'Moderate', 'Low'] }
                            }
                        }
                    }
                },
                required: ['toxicityScore', 'summary', 'negativeEntities']
            },
            dailyMissions: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        id: { type: Type.STRING },
                        title: { type: Type.STRING },
                        description: { type: Type.STRING },
                        xp: { type: Type.NUMBER },
                        category: { type: Type.STRING, enum: ['Content', 'Review', 'Social'] },
                        estimatedTime: { type: Type.STRING }
                    }
                }
            },
            competitors: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  strengths: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
              }
            },
            recommendations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  impact: { type: Type.STRING, enum: [ImpactLevel.HIGH, ImpactLevel.MEDIUM, ImpactLevel.LOW] },
                  actionItem: { type: Type.STRING }
                }
              }
            }
          },
          required: ["overallScore", "summary", "attributes", "simulations", "personas", "contentGaps", "platformPerformance", "llmPerformance", "localCompetitors", "citationOpportunities", "keywordHeist", "sentimentAudit", "dailyMissions", "competitors", "recommendations"]
        }
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response from AI");
    }

    const data = JSON.parse(text) as AnalysisResult;
    // Generate simple IDs for missions if not present
    if (data.dailyMissions) {
        data.dailyMissions = data.dailyMissions.map((m, i) => ({
            ...m,
            id: m.id || `mission-${i}`
        }));
    }
    return data;

  } catch (error) {
    console.error("Error analyzing business:", error);
    throw error;
  }
};

