                                    <p className={`text-xs mt-1 transition-all ${completedMissions.includes(mission.id) ? 'text-zinc-600' : 'text-zinc-400'}`}>
                                        {mission.description}
                                    </p>
                                    <div className="flex items-center gap-3 mt-3">
                                        <span className="text-[10px] text-zinc-500 font-mono flex items-center gap-1">
                                            <CalendarIcon className="w-3 h-3" />
                                            {mission.estimatedTime}
                                        </span>
                                        <span className="text-[10px] text-zinc-500 font-mono border border-zinc-800 px-1.5 rounded uppercase">
                                            {mission.category}
                                        </span>
                                    </div>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            {/* Tool: Smart Review Responder */}
            <div className="bg-surface border border-zinc-800 rounded-xl p-6 shadow-lg relative overflow-hidden flex flex-col">
                <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full blur-2xl"></div>
                <h3 className="text-sm font-bold text-zinc-300 mb-2 uppercase tracking-wide flex items-center gap-2">
                    <SparklesIcon className="w-4 h-4 text-indigo-400" />
                    Review Response Assistant
                </h3>
                <p className="text-xs text-zinc-500 mb-4">Paste a customer review below. We'll generate a reply using your high-value keywords to boost your SEO score.</p>

                <textarea 
                    className="w-full bg-zinc-900 border border-zinc-800 rounded-lg p-3 text-sm text-zinc-300 placeholder-zinc-600 focus:outline-none focus:border-indigo-500/50 mb-4 h-32 resize-none"
                    placeholder="Paste customer review here..."
                    value={reviewInput}
                    onChange={(e) => setReviewInput(e.target.value)}
                />

                <button 
                    onClick={generateResponse}
                    disabled={!reviewInput}
                    className={`w-full py-2 rounded font-bold text-xs uppercase tracking-wide transition-all mb-6
                    ${!reviewInput ? 'bg-zinc-800 text-zinc-600 cursor-not-allowed' : 'bg-white text-black hover:bg-zinc-200'}`}
                >
                    Generate Optimized Reply
                </button>

                {reviewResponse && (
                    <div className="mt-auto bg-indigo-500/10 border border-indigo-500/20 rounded-lg p-4 relative animate-fade-in">
                        <p className="text-xs text-indigo-200 leading-relaxed font-mono">
                            "{reviewResponse}"
                        </p>
                        <button className="absolute top-2 right-2 text-indigo-400 hover:text-white" onClick={() => navigator.clipboard.writeText(reviewResponse)}>
                            <CopyIcon className="w-4 h-4" />
                        </button>
                    </div>
                )}

                {!reviewResponse && (
                    <div className="mt-auto pt-4 border-t border-zinc-800">
                        <p className="text-[10px] font-bold text-zinc-500 uppercase mb-2">Keywords we will inject:</p>
                        <div className="flex flex-wrap gap-2">
                            {data.keywordHeist?.slice(0, 3).map((k, i) => (
                                <span key={i} className="text-[10px] px-2 py-0.5 rounded bg-zinc-800 text-zinc-400 border border-zinc-700">
                                    {k.term}
                                </span>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    </div>
  )

  const renderMap = () => {
    const mapData = [
      { x: 0, y: 0, name: businessName, rank: 0, z: 0 },
      ...(data.localCompetitors?.map(c => ({
        x: c.x,
        y: c.y,
        name: c.name,
        rank: c.rank,
        z: 0 // We don't use z for size anymore, we use rank in custom shape
      })) || [])
    ];

    return (
      <div className="space-y-6 animate-slide-up">
        <div className="bg-surface border border-zinc-800 rounded-xl p-1 h-[700px] flex flex-col shadow-2xl relative overflow-hidden">
            {/* Map Header Overlay */}
            <div className="absolute top-6 left-6 z-20 pointer-events-none">
                <h3 className="text-sm font-bold text-white uppercase tracking-wider flex items-center gap-2 bg-black/50 backdrop-blur-md px-3 py-1 rounded-full border border-zinc-800">
                    <div className="w-2 h-2 bg-rose-500 rounded-full animate-pulse"></div>
                    Competitor Radar
                </h3>
                <p className="text-zinc-500 text-[10px] mt-2 font-mono ml-2">PROXIMITY SCAN • 5KM RADIUS</p>
            </div>

             {/* Cardinal Directions */}
             <div className="absolute top-4 left-1/2 -translate-x-1/2 text-zinc-700 font-mono text-xs font-bold pointer-events-none z-10">N</div>
             <div className="absolute bottom-4 left-1/2 -translate-x-1/2 text-zinc-700 font-mono text-xs font-bold pointer-events-none z-10">S</div>
             <div className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-700 font-mono text-xs font-bold pointer-events-none z-10">W</div>
             <div className="absolute right-4 top-1/2 -translate-y-1/2 text-zinc-700 font-mono text-xs font-bold pointer-events-none z-10">E</div>


            <div className="flex-grow bg-[#050505] rounded-lg relative overflow-hidden cursor-crosshair">
                {/* Background Grid Pattern */}
                <div className="absolute inset-0 bg-[linear-gradient(to_right,#18181b_1px,transparent_1px),linear-gradient(to_bottom,#18181b_1px,transparent_1px)] bg-[size:40px_40px] opacity-30"></div>
                <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-900/10 via-black to-black"></div>

                {/* Sonar Rings */}
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[30%] h-[30%] rounded-full border border-zinc-800/60 pointer-events-none"></div>
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[60%] h-[60%] rounded-full border border-zinc-800/40 pointer-events-none"></div>
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[90%] h-[90%] rounded-full border border-zinc-800/20 pointer-events-none"></div>

                {/* Axes Lines */}
                <div className="absolute top-0 left-1/2 w-px h-full bg-indigo-500/10 z-0"></div>
                <div className="absolute left-0 top-1/2 h-px w-full bg-indigo-500/10 z-0"></div>

                <ResponsiveContainer width="100%" height="100%">
                  <ScatterChart margin={{ top: 40, right: 40, bottom: 40, left: 40 }}>
                    <XAxis type="number" dataKey="x" name="Longitude" hide domain={[-12, 12]} />
                    <YAxis type="number" dataKey="y" name="Latitude" hide domain={[-12, 12]} />
                    <Tooltip 
                        cursor={{ strokeDasharray: '3 3', stroke: '#52525b' }} 
                        content={({ active, payload }) => {
                        if (active && payload && payload.length) {
                            const data = payload[0].payload;
                            return (
                            <div className="bg-zinc-900/95 backdrop-blur border border-zinc-700 p-3 rounded shadow-2xl z-50">
                                <p className="font-bold text-white text-sm mb-1">{data.name}</p>
                                <div className="flex flex-col gap-1">
                                    <p className={`text-xs font-mono font-bold ${data.rank === 0 ? 'text-indigo-400' : 'text-rose-400'}`}>
                                        {data.rank === 0 ? "TARGET BUSINESS" : `RANK #${data.rank}`}
                                    </p>
                                    {data.rank !== 0 && (
                                        <p className="text-[10px] text-zinc-500 font-mono">
                                            Approx. Distance: {Math.sqrt(data.x*data.x + data.y*data.y).toFixed(1)} km
                                        </p>
                                    )}
                                </div>
                            </div>
                            );
                        }
                        return null;
                        }}
                    />
                    <Scatter name="Competitors" data={mapData} shape={<CustomMapNode />} />
                  </ScatterChart>
                </ResponsiveContainer>

                {/* Legend */}
                <div className="absolute bottom-6 right-6 flex flex-col gap-2 bg-black/80 backdrop-blur-md p-3 rounded-lg border border-zinc-800 shadow-xl pointer-events-none">
                     <div className="flex items-center gap-2">
                        <div className="w-4 h-4 rounded-full bg-indigo-500 flex items-center justify-center text-[8px] font-bold text-white">YOU</div>
                        <span className="text-xs text-zinc-300 font-mono">YOUR BUSINESS</span>
                     </div>
                     <div className="flex items-center gap-2">
                        <div className="w-4 h-4 rounded-full border border-rose-500 text-rose-500 flex items-center justify-center text-[8px] font-bold">1</div>
                        <span className="text-xs text-zinc-300 font-mono">TOP 3 RANK</span>
                     </div>
                     <div className="flex items-center gap-2">
                        <div className="w-4 h-4 rounded-full border border-zinc-600 text-zinc-500 flex items-center justify-center text-[8px] font-bold">8</div>
                        <span className="text-xs text-zinc-300 font-mono">LOWER RANK</span>
                     </div>
                </div>
            </div>
        </div>

        {/* Competitor List below map */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
             {data.localCompetitors?.sort((a,b) => a.rank - b.rank).map((comp, idx) => (
                 <div key={idx} className="bg-surface border border-zinc-800 p-3 rounded-lg flex items-center justify-between hover:border-zinc-600 transition-colors group">
                     <div className="flex items-center gap-3">
                         <div className={`w-8 h-8 rounded flex items-center justify-center font-bold text-sm border
                             ${comp.rank <= 3 ? 'bg-rose-500/10 border-rose-500/30 text-rose-500' : 'bg-zinc-900 border-zinc-700 text-zinc-500'}`}>
                             #{comp.rank}
                         </div>
                         <div>
                             <h4 className="text-zinc-200 font-medium text-sm group-hover:text-white truncate max-w-[150px]">{comp.name}</h4>
                             <p className="text-[10px] text-zinc-500 font-mono">{comp.distance} away</p>
                         </div>
                     </div>
                 </div>
             ))}
        </div>
      </div>
    );
  };

  const renderLLMs = () => (
    <div className="space-y-6 animate-slide-up">
      <div className="bg-surface border border-zinc-800 rounded-xl p-6 shadow-lg">
        <h3 className="text-sm font-bold text-zinc-300 mb-8 uppercase tracking-wide">Model Analysis</h3>
        <div className="space-y-4">
          {data.llmPerformance?.map((llm, idx) => (
            <div key={idx} className={`group border rounded-lg overflow-hidden transition-all bg-zinc-900/30 ${llm.model === 'ChatGPT' ? 'hover:border-emerald-500/50 border-zinc-800' : llm.model === 'Gemini' ? 'hover:border-blue-500/50 border-zinc-800' : 'hover:border-teal-500/50 border-zinc-800'}`}>
               <div className="px-6 py-5 flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
                  <div className="flex items-center gap-5">
                    <div className={`w-12 h-12 rounded-lg flex items-center justify-center text-white font-bold text-xl shadow-lg
                        ${llm.model === 'ChatGPT' ? 'bg-emerald-600 shadow-emerald-900/20' : llm.model === 'Gemini' ? 'bg-blue-600 shadow-blue-900/20' : 'bg-teal-700 shadow-teal-900/20'}`}>
                       {llm.model[0]}
                    </div>
                    <div>
                        <h4 className="font-bold text-white text-lg">{llm.model}</h4>
                        <div className="flex items-center gap-3 mt-1">
                           <div className="w-48 bg-zinc-900 h-2 rounded-full overflow-hidden border border-zinc-800">
                               <div 
                                className={`h-full rounded-full ${llm.model === 'ChatGPT' ? 'bg-emerald-500' : llm.model === 'Gemini' ? 'bg-blue-500' : 'bg-teal-500'}`} 
                                style={{ width: `${llm.score}%` }}></div>
                           </div>
                           <span className="text-xs text-zinc-400 font-mono font-bold">{llm.score} PTS</span>
                        </div>
                    </div>
                  </div>
                  <span className={`px-3 py-1 text-[10px] font-bold font-mono border rounded uppercase tracking-wider
                     ${llm.status === 'Top Choice' ? 'border-emerald-500/30 text-emerald-400 bg-emerald-500/10' : 'border-zinc-800 text-zinc-500'}`}>
                     {llm.status}
                  </span>
               </div>
               <div className="px-6 pb-6 pt-2">
                  <p className="text-zinc-400 text-sm leading-relaxed border-l-2 border-zinc-800 pl-4 group-hover:border-zinc-600 transition-colors">{llm.details}</p>
               </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  const renderCitations = () => (
    <div className="space-y-6 animate-slide-up">
        <div className="bg-surface border border-zinc-800 p-6 rounded-xl shadow-lg relative overflow-hidden">
             <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full blur-2xl"></div>
            <h3 className="text-sm font-bold text-zinc-300 mb-2 uppercase tracking-wide relative z-10">Knowledge Graph Sources</h3>
            <p className="text-zinc-500 text-sm mb-6 max-w-2xl font-light relative z-10">
                Optimize these sources to establish entity authority within the vector space of large language models.
            </p>

            <div className="grid grid-cols-1 gap-3 relative z-10">
                {data.citationOpportunities?.map((cit, idx) => (
                    <div key={idx} className="bg-zinc-900/50 rounded-lg border border-zinc-800 p-5 flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between hover:border-indigo-500/30 transition-all group">
                        <div className="flex items-center gap-4">
                            <div className="w-10 h-10 bg-zinc-800 rounded-full flex items-center justify-center border border-zinc-700 text-zinc-400 group-hover:bg-indigo-500/20 group-hover:text-indigo-400 group-hover:border-indigo-500/30 transition-all">
                                <GlobeIcon className="w-4 h-4" />
                            </div>
                            <div>
                                <h4 className="font-bold text-zinc-200 text-sm group-hover:text-indigo-300 transition-colors">{cit.siteName}</h4>
                                <a href={`https://${cit.domain}`} target="_blank" rel="noreferrer" className="text-zinc-500 text-xs hover:text-white transition-colors font-mono">{cit.domain}</a>
                            </div>
                        </div>

                        <div className="w-full sm:w-auto flex flex-col items-start sm:items-end gap-1">
                            <span className={`text-[10px] font-bold uppercase tracking-widest px-2 py-0.5 rounded border ${cit.priority === ImpactLevel.HIGH ? 'border-indigo-500/30 text-indigo-400 bg-indigo-500/10' : 'border-zinc-800 text-zinc-500'}`}>
                                {cit.priority} Priority
                            </span>
                            <p className="text-xs text-zinc-600 max-w-xs text-right sm:text-right font-mono">{cit.reason}</p>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    </div>
  );

  const renderDeepDive = () => {
     return (
        <div className="space-y-6 animate-slide-up">

            {/* Feature 3: Competitor Keyword Heist */}
            <div className="bg-surface border border-zinc-800 rounded-xl p-6 shadow-lg relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-amber-500 to-orange-500"></div>
                <div className="mb-6">
                    <h3 className="text-sm font-bold text-white mb-2 uppercase tracking-wide flex items-center gap-2">
                        <TargetIcon className="w-4 h-4 text-amber-500" />
                        Competitor Keyword Heist
                    </h3>
                    <p className="text-zinc-500 text-sm">
                        Semantic gap analysis. Identify adjectives the AI assigns to your competitors that are missing from your brand profile.
                    </p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {/* The Gap */}
                    <div className="bg-zinc-900/50 rounded-lg p-4 border border-zinc-800">
                        <h4 className="text-xs font-bold text-amber-500 uppercase tracking-widest mb-4 border-b border-zinc-800 pb-2">Opportunity Gap (Stolen by Competitors)</h4>
                        <div className="flex flex-wrap gap-2">
                            {data.keywordHeist?.filter(k => k.owner === 'Competitor').map((k, idx) => (
                                <span key={idx} className="px-3 py-1.5 rounded bg-amber-500/10 border border-amber-500/30 text-amber-400 text-xs font-mono font-bold flex items-center gap-2">
                                    {k.term}
                                    <span className="opacity-50 text-[10px]">{k.opportunityScore}%</span>
                                </span>
                            ))}
                        </div>
                        {data.keywordHeist?.filter(k => k.owner === 'Competitor').length === 0 && (
                             <p className="text-zinc-600 text-xs italic">No clear semantic gaps found.</p>
                        )}
                    </div>

                     {/* Your Defense */}
                     <div className="bg-zinc-900/50 rounded-lg p-4 border border-zinc-800">
                        <h4 className="text-xs font-bold text-indigo-500 uppercase tracking-widest mb-4 border-b border-zinc-800 pb-2">Your Semantic Territory (What you own)</h4>
                        <div className="flex flex-wrap gap-2">
                            {data.keywordHeist?.filter(k => k.owner === 'You' || k.owner === 'Shared').map((k, idx) => (
                                <span key={idx} className={`px-3 py-1.5 rounded border text-xs font-mono font-bold flex items-center gap-2
                                    ${k.owner === 'Shared' ? 'bg-zinc-800 border-zinc-700 text-zinc-400' : 'bg-indigo-500/10 border-indigo-500/30 text-indigo-400'}`}>
                                    {k.term}
                                    {k.owner === 'Shared' && <span className="opacity-50 text-[10px] ml-1">(SHARED)</span>}
                                </span>
                            ))}
                        </div>
                    </div>
                </div>
            </div>

            {/* Feature 5: Review Sentiment Training Data Audit */}
            <div className="bg-surface border border-zinc-800 rounded-xl p-6 shadow-lg relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-rose-600 to-rose-900"></div>
                <div className="mb-6 flex justify-between items-start">
                    <div>
                        <h3 className="text-sm font-bold text-white mb-2 uppercase tracking-wide flex items-center gap-2">
                            <ActivityIcon className="w-4 h-4 text-rose-500" />
                            Training Data Toxicity Audit
                        </h3>
                        <p className="text-zinc-500 text-sm max-w-2xl">
                            LLMs train on your reviews. Recurring negative entities become permanent brand associations. 
                            <span className="text-rose-400 ml-1">High toxicity scores reduce ranking visibility.</span>
                        </p>
                    </div>
                    <div className="text-right">
                        <div className="text-3xl font-bold text-white">{data.sentimentAudit?.toxicityScore}%</div>
                        <div className="text-[10px] font-mono text-zinc-500 uppercase">Toxicity Score</div>
                    </div>
                </div>

                <div className="w-full bg-zinc-900 h-2 rounded-full mb-8 overflow-hidden">
                    <div 
                        className={`h-full transition-all duration-1000 ${data.sentimentAudit?.toxicityScore > 50 ? 'bg-rose-600' : data.sentimentAudit?.toxicityScore > 20 ? 'bg-amber-500' : 'bg-emerald-500'}`} 
                        style={{ width: `${data.sentimentAudit?.toxicityScore}%` }}
                    ></div>
                </div>

                <div className="space-y-3">
                    <h4 className="text-xs font-bold text-zinc-400 uppercase tracking-widest mb-2">Detected Negative Entities (Contaminants)</h4>
                    {data.sentimentAudit?.negativeEntities.map((entity, idx) => (
                         <div key={idx} className="flex items-center justify-between p-3 bg-zinc-900/50 border border-zinc-800 rounded hover:border-rose-900/50 transition-colors">
                             <div className="flex items-center gap-3">
                                 <div className="w-2 h-2 rounded-full bg-rose-500 animate-pulse"></div>
                                 <span className="text-sm font-bold text-zinc-200">"{entity.term}"</span>
                             </div>
                             <div className="flex items-center gap-4">
                                 <span className="text-xs font-mono text-zinc-500">{entity.frequency}</span>
                                 <span className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded border
                                     ${entity.impact === 'Critical' ? 'bg-rose-500/10 border-rose-500/30 text-rose-400' : 
                                       entity.impact === 'Moderate' ? 'bg-amber-500/10 border-amber-500/30 text-amber-400' : 
                                       'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>
                                     {entity.impact} Impact
                                 </span>
                             </div>
                         </div>
                    ))}
                    {data.sentimentAudit?.negativeEntities.length === 0 && (
                        <div className="flex items-center gap-2 p-3 bg-emerald-500/5 border border-emerald-500/20 rounded">
                            <CheckCircleIcon className="w-4 h-4 text-emerald-500" />
                            <span className="text-sm text-emerald-400">Clean bill of health. No recurring negative entities found in simulated training data.</span>
                        </div>
                    )}
                </div>
            </div>
        </div>
     )
  }

  return (
    <div className="space-y-8 pb-12">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 pt-4">
        <div>
           <h2 className="text-3xl font-bold text-white tracking-tight">{businessName}</h2>
           <div className="flex items-center gap-2 mt-2">
              <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_8px_#10b981]"></span>
              <p className="text-zinc-500 text-xs font-mono uppercase tracking-wide">Analysis Complete</p>
           </div>
        </div>
        <button 
          onClick={onReset}
          className="flex items-center gap-2 px-5 py-2.5 text-xs font-bold tracking-wide text-zinc-900 bg-white rounded hover:bg-zinc-200 transition-colors shadow-[0_0_15px_rgba(255,255,255,0.1)]"
        >
          <RefreshCwIcon className="w-3 h-3" />
          NEW AUDIT
        </button>
      </div>

      {/* Tabs */}
      <div className="border-b border-zinc-800">
        <nav className="-mb-px flex space-x-8 overflow-x-auto" aria-label="Tabs">
          {[
            { id: 'overview', label: 'Overview' },
            { id: 'missions', label: 'Daily Missions', icon: <FlameIcon className="w-4 h-4 text-orange-500" /> },
            { id: 'deepdive', label: 'Deep Dive' },
            { id: 'llms', label: 'Models' },
            { id: 'map', label: 'Map' },
            { id: 'citations', label: 'Citations' }
          ].map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`${
                activeTab === tab.id
                  ? 'border-indigo-500 text-white'
                  : 'border-transparent text-zinc-500 hover:text-zinc-300 hover:border-zinc-700'
              } whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm transition-colors uppercase tracking-wider flex items-center gap-2`}
            >
              {tab.icon}
              {tab.label}
              {tab.id === 'missions' && completedMissions.length === 0 && <span className="w-1.5 h-1.5 rounded-full bg-orange-500 animate-pulse"></span>}
            </button>
          ))}
        </nav>
      </div>

      {/* Content Area */}
      <div className="mt-8 min-h-[500px]">
        {activeTab === 'overview' && renderOverview()}
        {activeTab === 'missions' && renderMissions()}
        {activeTab === 'deepdive' && renderDeepDive()}
        {activeTab === 'llms' && renderLLMs()}
        {activeTab === 'map' && renderMap()}
        {activeTab === 'citations' && renderCitations()}
      </div>

    </div>
  );
};

export default Dashboard;

export interface BusinessInfo {
  name: string;
  location: string;
  category: string;
  website?: string;
  keywords?: string;
}

export interface Simulation {
  query: string;
  aiResponse: string;
  rank: 'Top Recommendation' | 'Mentioned' | 'Not Found';
}

export enum ImpactLevel {
  HIGH = 'High',
  MEDIUM = 'Medium',
  LOW = 'Low'
}

export interface Recommendation {
  title: string;
  description: string;
  impact: ImpactLevel;
  actionItem: string;
}

export interface Competitor {
  name: string;
  strengths: string[];
}

export interface PersonaSimulation {
  personaName: string;
  userIntent: string;
  simulatedQuery: string;
  aiResponseSummary: string;
  brandMentioned: boolean;
}

export interface ContentGap {
  missingElement: string;
  importance: ImpactLevel;
  fix: string;
}

export interface PlatformPerformance {
  platform: 'Chat Interfaces' | 'Voice Search' | 'Traditional Search';
  score: number;
  status: 'Optimized' | 'Needs Work' | 'Invisible';
}

// New Types
export interface LLMPerformance {
  model: 'ChatGPT' | 'Gemini' | 'Perplexity';
  status: 'Top Choice' | 'Option' | 'Hidden';
  details: string;
  score: number; // 0-100 visibility score
}

export interface CitationOpportunity {
  siteName: string;
  domain: string;
  type: 'Directory' | 'Social' | 'Forum' | 'Health/Niche';
  priority: ImpactLevel;
  reason: string;
}

export interface LocalCompetitorLocation {
  name: string;
  rank: number;
  distance: string; // e.g., "0.5 miles"
  x: number; // Relative coordinate for map visualization (-10 to 10)
  y: number; // Relative coordinate for map visualization (-10 to 10)
}

// Feature 3: Keyword Heist
export interface KeywordGap {
  term: string;
  owner: 'Competitor' | 'You' | 'Shared';
  searchVolume: 'High' | 'Medium' | 'Low';
  opportunityScore: number; // 0-100
}

// Feature 5: Sentiment Audit
export interface NegativeEntity {
  term: string; // e.g. "Rude", "Slow", "Expensive"
  frequency: string; // e.g. "14% of reviews"
  impact: 'Critical' | 'Moderate' | 'Low';
}

// New Rich Attribute Interface for clearer KPIs
export interface AttributeDetail {
  score: number;
  label: string; // e.g. "Excellent", "Needs Work"
  explanation: string; // Simple English explanation
  action: string; // Immediate next step
}

// Recurring Usage Feature: Daily Missions
export interface DailyMission {
  id: string;
  title: string;
  description: string;
  xp: number; // Gamification points 10-50
  category: 'Content' | 'Review' | 'Social';
  estimatedTime: string; // e.g. "2 mins"
}

// New Feature: AI Content Studio
export interface SocialPostIdea {
  platform: 'Instagram' | 'LinkedIn' | 'GMB';
  focusKeyword: string;
  caption: string;
  hashtags: string[];
  imageIdea: string;
  whyThisWorks: string; // Connects back to the audit gap
}

// New Feature: Voice Simulator
export interface VoiceSimulation {
  query: string;
  script: string; // What the AI "Says"
  voiceParams: {
    pitch: number;
    rate: number;
  };
}

export interface AnalysisResult {
  overallScore: number;
  summary: string;
  attributes: {
    authority: AttributeDetail;
    consistency: AttributeDetail;
    sentiment: AttributeDetail;
    relevance: AttributeDetail;
    citations: AttributeDetail;
  };
  simulations: Simulation[];
  personas: PersonaSimulation[];
  contentGaps: ContentGap[];
  platformPerformance: PlatformPerformance[];

  // New Fields
  llmPerformance: LLMPerformance[];
  citationOpportunities: CitationOpportunity[];
  localCompetitors: LocalCompetitorLocation[];

  // High Value Features
  keywordHeist: KeywordGap[];
  sentimentAudit: {
    toxicityScore: number; // 0-100 (0 is clean, 100 is toxic)
    negativeEntities: NegativeEntity[];
    summary: string;
  };

  // Recurring Usage
  dailyMissions: DailyMission[];

  // SaaS Value Features
  contentStrategy: SocialPostIdea[];
  voiceSimulation: VoiceSimulation;

  competitors: Competitor[];
  recommendations: Recommendation[];
}

export interface AnalysisState {
  loading: boolean;
  error: string | null;
  result: AnalysisResult | null;
}

