import React, { useState, useRef } from 'react';
import { BusinessInfo } from '../types';
import { MapPinIcon, GlobeIcon, SearchIcon, SparklesIcon } from './Icons';

interface Props {
  onSubmit: (info: BusinessInfo) => void;
  isLoading: boolean;
}

const BusinessForm: React.FC<Props> = ({ onSubmit, isLoading }) => {
  const [info, setInfo] = useState<BusinessInfo>({
    name: '',
    location: '',
    category: '',
    website: '',
    keywords: '',
    images: []
  });
  const [previewImages, setPreviewImages] = useState<string[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const files = Array.from(e.target.files).slice(0, 3); // Max 3 images
      const promises = files.map(file => {
        return new Promise<string>((resolve, reject) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.onerror = reject;
          reader.readAsDataURL(file);
        });
      });

      Promise.all(promises).then(base64Images => {
        setInfo(prev => ({ ...prev, images: base64Images }));
        setPreviewImages(base64Images);
      });
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (info.name && info.location && info.category) {
      onSubmit(info);
    }
  };

  return (
    <div className="w-full max-w-xl mx-auto">
      <div className="bg-surface border border-border rounded-xl p-1 shadow-2xl">
        <form onSubmit={handleSubmit} className="bg-background rounded-lg p-6 sm:p-8 space-y-6 border border-zinc-900">

          <div className="space-y-5">
            <div className="space-y-1.5">
              <label className="text-xs font-semibold text-zinc-400 uppercase tracking-wider ml-1">Business Name</label>
              <input
                type="text"
                required
                placeholder="e.g. Joe's Coffee Spot"
                className="w-full bg-zinc-900/50 border border-zinc-800 rounded-lg px-4 py-3 text-white placeholder-zinc-600 focus:outline-none focus:ring-1 focus:ring-white focus:border-white transition-all font-medium"
                value={info.name}
                onChange={(e) => setInfo(prev => ({ ...prev, name: e.target.value }))}
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              <div className="space-y-1.5">
                <label className="text-xs font-semibold text-zinc-400 uppercase tracking-wider ml-1">Category</label>
                <div className="relative">
                  <input
                    type="text"
                    required
                    placeholder="e.g. Coffee Shop"
                    className="w-full bg-zinc-900/50 border border-zinc-800 rounded-lg pl-10 pr-4 py-3 text-white placeholder-zinc-600 focus:outline-none focus:ring-1 focus:ring-white focus:border-white transition-all font-medium"
                    value={info.category}
                    onChange={(e) => setInfo(prev => ({ ...prev, category: e.target.value }))}
                  />
                  <SearchIcon className="w-4 h-4 text-zinc-500 absolute left-3 top-3.5" />
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-xs font-semibold text-zinc-400 uppercase tracking-wider ml-1">Location</label>
                <div className="relative">
                  <input
                    type="text"
                    required
                    placeholder="e.g. Austin, TX"
                    className="w-full bg-zinc-900/50 border border-zinc-800 rounded-lg pl-10 pr-4 py-3 text-white placeholder-zinc-600 focus:outline-none focus:ring-1 focus:ring-white focus:border-white transition-all font-medium"
                    value={info.location}
                    onChange={(e) => setInfo(prev => ({ ...prev, location: e.target.value }))}
                  />
                  <MapPinIcon className="w-4 h-4 text-zinc-500 absolute left-3 top-3.5" />
                </div>
              </div>
            </div>

            <div className="space-y-1.5">
              <label className="text-xs font-semibold text-zinc-400 uppercase tracking-wider ml-1">Website (Optional)</label>
              <div className="relative">
                <input
                  type="url"
                  placeholder="https://..."
                  className="w-full bg-zinc-900/50 border border-zinc-800 rounded-lg pl-10 pr-4 py-3 text-white placeholder-zinc-600 focus:outline-none focus:ring-1 focus:ring-white focus:border-white transition-all font-medium"
                  value={info.website}
                  onChange={(e) => setInfo(prev => ({ ...prev, website: e.target.value }))}
                />
                <GlobeIcon className="w-4 h-4 text-zinc-500 absolute left-3 top-3.5" />
              </div>
            </div>

             <div className="space-y-1.5">
                <label className="text-xs font-semibold text-zinc-400 uppercase tracking-wider ml-1">Target Keywords (Optional)</label>
                <input
                    type="text"
                    placeholder="e.g. 'best espresso', 'cheap latte'"
                    className="w-full bg-zinc-900/50 border border-zinc-800 rounded-lg px-4 py-3 text-white placeholder-zinc-600 focus:outline-none focus:ring-1 focus:ring-white focus:border-white transition-all font-medium"
                    value={info.keywords || ''}
                    onChange={(e) => setInfo(prev => ({ ...prev, keywords: e.target.value }))}
                />
            </div>

            {/* Visual GEO Input */}
            <div className="space-y-1.5">
                <label className="text-xs font-semibold text-zinc-400 uppercase tracking-wider ml-1 flex items-center justify-between">
                    <span>Visual Audit (GMB Photos)</span>
                    <span className="text-[10px] text-emerald-500 bg-emerald-500/10 px-2 py-0.5 rounded border border-emerald-500/20">NEW FEATURE</span>
                </label>
                <div 
                    onClick={() => fileInputRef.current?.click()}
                    className="w-full bg-zinc-900/50 border border-dashed border-zinc-700 rounded-lg px-4 py-6 flex flex-col items-center justify-center cursor-pointer hover:bg-zinc-800/50 hover:border-zinc-500 transition-all group"
                >
                    <input 
                        type="file" 
                        ref={fileInputRef} 
                        onChange={handleImageUpload} 
                        className="hidden" 
                        multiple 
                        accept="image/*"
                    />
                    {previewImages.length > 0 ? (
                        <div className="flex gap-2">
                            {previewImages.map((img, idx) => (
                                <img key={idx} src={img} alt="Preview" className="w-16 h-16 object-cover rounded border border-zinc-700" />
                            ))}
                        </div>
                    ) : (
                        <>
                            <div className="w-10 h-10 rounded-full bg-zinc-800 flex items-center justify-center mb-2 group-hover:scale-110 transition-transform">
                                <SparklesIcon className="w-5 h-5 text-indigo-400" />
                            </div>
                            <p className="text-zinc-400 text-xs font-medium">Click to upload business photos (Max 3)</p>
                            <p className="text-zinc-600 text-[10px] mt-1">AI will analyze your visual "vibe"</p>
                        </>
                    )}
                </div>
            </div>
          </div>

          <div className="pt-2">
            <button
              type="submit"
              disabled={isLoading}
              className={`w-full py-4 px-6 rounded-lg font-bold text-sm tracking-wide transition-all
                ${isLoading 
                  ? 'bg-zinc-800 text-zinc-500 cursor-not-allowed border border-zinc-700' 
                  : 'bg-white text-black hover:bg-zinc-200 border border-transparent shadow-[0_0_15px_rgba(255,255,255,0.1)]'
                }`}
            >
              {isLoading ? (
                <span className="flex items-center justify-center gap-2">
                  <span className="w-4 h-4 border-2 border-zinc-400 border-t-zinc-800 rounded-full animate-spin"></span>
                  SCANNING VISUAL & TEXT DATA...
                </span>
              ) : (
                'INITIATE ANALYSIS'
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default BusinessForm;

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, BusinessInfo, ImpactLevel } from "../types";

const getApiKey = (): string => {
  const key = process.env.API_KEY;
  if (!key) {
    throw new Error("API Key not found. Please set REACT_APP_GEMINI_API_KEY.");
  }
  return key;
};

export const analyzeBusinessVisibility = async (business: BusinessInfo): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });

  const promptText = `
    Analyze the "LLM Visibility" (GEO - Generative Engine Optimization) for:

    Business: ${business.name}
    Location: ${business.location}
    Category: ${business.category}
    ${business.website ? `Website: ${business.website}` : ''}
    ${business.keywords ? `Keywords: ${business.keywords}` : ''}

    Target Audience: The user is a business owner who is NOT technical. 
    Crucial Requirement: For every metric, explain "Why it matters" and "What to do" in simple, non-jargon English.

    Task: Simulate an advanced SEO audit for AI engines.

    1.  **Research**: Use Google Search to find real info, reviews, citations, and competitors.
    2.  **LLM Ranking**: Simulate how this business appears specifically in ChatGPT, Gemini, and Perplexity.
    3.  **Local Map**: Identify 10-15 key competitors.
    4.  **KPI Analysis**: For Authority, Consistency, Sentiment, Relevance, and Citations, provide a score (0-100), a label, explanation, and fix.
    5.  **Keyword Heist**: Identify adjectives AI associates with competitors but not the user.
    6.  **Training Data Audit**: Scan for negative words in reviews that might poison AI answers.
    7.  **Daily Missions**: Create 4 specific, actionable tasks.
    8.  **Content Studio Strategy**: Create 3 completely written social media posts (Instagram, LinkedIn, GMB) using *missing* keywords.
    9.  **Voice Search Simulation**: Script what Siri/Google Assistant would say.
    10. **Visual Audit**: If images are provided, analyze their "vibe", "cleanliness", and "premium feel". If no images, simulate based on typical category standards.
    11. **Hallucination Monitor (Fact Check)**: Simulate 3-5 specific factual questions (e.g., "Do they have parking?", "Are they dog friendly?", "Do they take reservations?") and provide what the AI *thinks* is the answer based on training data.
    12. **PAA Hijacker**: Generate 3 high-intent "People Also Ask" questions for Voice Search and provide the exact "Position Zero" 40-word answer to paste on their website.

    Return strict JSON.
  `;

  const parts: any[] = [{ text: promptText }];

  // Add images to the payload if they exist
  if (business.images && business.images.length > 0) {
    business.images.forEach(base64Str => {
      // Remove header if present (e.g., "data:image/jpeg;base64,")
      const base64Data = base64Str.split(',')[1];
      parts.push({
        inlineData: {
          mimeType: 'image/jpeg', // Assuming jpeg for simplicity, or detect from header
          data: base64Data
        }
      });
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: parts },
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
