                            LLMs train on your reviews. Recurring negative entities become permanent brand associations. 
                            <span className="text-rose-400 ml-1">High toxicity scores reduce ranking visibility.</span>
                        </p>
                    </div>
                    <div className="text-right">
                        <div className="text-3xl font-bold text-white">{data.sentimentAudit?.toxicityScore}%</div>
                        <div className="text-[10px] font-mono text-zinc-500 uppercase">Toxicity Score</div>
                    </div>
                </div>

                <div className="w-full bg-zinc-900 h-2 rounded-full mb-8 overflow-hidden">
                    <div 
                        className={`h-full transition-all duration-1000 ${data.sentimentAudit?.toxicityScore > 50 ? 'bg-rose-600' : data.sentimentAudit?.toxicityScore > 20 ? 'bg-amber-500' : 'bg-emerald-500'}`} 
                        style={{ width: `${data.sentimentAudit?.toxicityScore}%` }}
                    ></div>
                </div>

                <div className="space-y-3">
                    <h4 className="text-xs font-bold text-zinc-400 uppercase tracking-widest mb-2">Detected Negative Entities (Contaminants)</h4>
                    {data.sentimentAudit?.negativeEntities.map((entity, idx) => (
                         <div key={idx} className="flex items-center justify-between p-3 bg-zinc-900/50 border border-zinc-800 rounded hover:border-rose-900/50 transition-colors">
                             <div className="flex items-center gap-3">
                                 <div className="w-2 h-2 rounded-full bg-rose-500 animate-pulse"></div>
                                 <span className="text-sm font-bold text-zinc-200">"{entity.term}"</span>
                             </div>
                             <div className="flex items-center gap-4">
                                 <span className="text-xs font-mono text-zinc-500">{entity.frequency}</span>
                                 <span className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded border
                                     ${entity.impact === 'Critical' ? 'bg-rose-500/10 border-rose-500/30 text-rose-400' : 
                                       entity.impact === 'Moderate' ? 'bg-amber-500/10 border-amber-500/30 text-amber-400' : 
                                       'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>
                                     {entity.impact} Impact
                                 </span>
                             </div>
                         </div>
                    ))}
                    {data.sentimentAudit?.negativeEntities.length === 0 && (
                        <div className="flex items-center gap-2 p-3 bg-emerald-500/5 border border-emerald-500/20 rounded">
                            <CheckCircleIcon className="w-4 h-4 text-emerald-500" />
                            <span className="text-sm text-emerald-400">Clean bill of health. No recurring negative entities found in simulated training data.</span>
                        </div>
                    )}
                </div>
            </div>
        </div>
     )
  }

  return (
    <div className="space-y-8 pb-12">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 pt-4">
        <div>
           <h2 className="text-3xl font-bold text-white tracking-tight">{businessName}</h2>
           <div className="flex items-center gap-2 mt-2">
              <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_8px_#10b981]"></span>
              <p className="text-zinc-500 text-xs font-mono uppercase tracking-wide">Analysis Complete</p>
           </div>
        </div>
        <button 
          onClick={onReset}
          className="flex items-center gap-2 px-5 py-2.5 text-xs font-bold tracking-wide text-zinc-900 bg-white rounded hover:bg-zinc-200 transition-colors shadow-[0_0_15px_rgba(255,255,255,0.1)]"
        >
          <RefreshCwIcon className="w-3 h-3" />
          NEW AUDIT
        </button>
      </div>

      {/* Tabs */}
      <div className="border-b border-zinc-800">
        <nav className="-mb-px flex space-x-8 overflow-x-auto" aria-label="Tabs">
          {[
            { id: 'overview', label: 'Overview' },
            { id: 'studio', label: 'Creator Studio', icon: <PenToolIcon className="w-4 h-4 text-indigo-400" /> },
            { id: 'missions', label: 'Missions', icon: <FlameIcon className="w-4 h-4 text-orange-500" /> },
            { id: 'visual', label: 'Visual', icon: <SparklesIcon className="w-4 h-4 text-emerald-500" /> },
            { id: 'deepdive', label: 'Deep Dive' },
            { id: 'llms', label: 'Models' },
            { id: 'map', label: 'Map' },
            { id: 'citations', label: 'Citations' }
          ].map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`${
                activeTab === tab.id
                  ? 'border-indigo-500 text-white'
                  : 'border-transparent text-zinc-500 hover:text-zinc-300 hover:border-zinc-700'
              } whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm transition-colors uppercase tracking-wider flex items-center gap-2`}
            >
              {tab.icon}
              {tab.label}
              {tab.id === 'missions' && completedMissions.length === 0 && <span className="w-1.5 h-1.5 rounded-full bg-orange-500 animate-pulse"></span>}
              {tab.id === 'studio' && <span className="text-[9px] bg-indigo-500 text-white px-1 rounded ml-1">NEW</span>}
              {tab.id === 'visual' && <span className="text-[9px] bg-emerald-500 text-white px-1 rounded ml-1">NEW</span>}
            </button>
          ))}
        </nav>
      </div>

      {/* Content Area */}
      <div className="mt-8 min-h-[500px]">
        {activeTab === 'overview' && renderOverview()}
        {activeTab === 'studio' && renderStudio()}
        {activeTab === 'missions' && renderMissions()}
        {activeTab === 'visual' && renderVisual()}
        {activeTab === 'deepdive' && renderDeepDive()}
        {activeTab === 'llms' && renderLLMs()}
        {activeTab === 'map' && renderMap()}
        {activeTab === 'citations' && renderCitations()}
      </div>

    </div>
  );
};

export default Dashboard;

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, BusinessInfo, ImpactLevel } from "../types";

const getApiKey = (): string => {
  const key = process.env.API_KEY;
  if (!key) {
    throw new Error("API Key not found. Please set REACT_APP_GEMINI_API_KEY.");
  }
  return key;
};

export const analyzeBusinessVisibility = async (business: BusinessInfo): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });

  const promptText = `
    Analyze the "LLM Visibility" (GEO - Generative Engine Optimization) for:

    Business: ${business.name}
    Location: ${business.location}
    Category: ${business.category}
    ${business.website ? `Website: ${business.website}` : ''}
    ${business.keywords ? `Keywords: ${business.keywords}` : ''}

    Target Audience: The user is a business owner who is NOT technical. 
    Crucial Requirement: For every metric, explain "Why it matters" and "What to do" in simple, non-jargon English.

    **CRITICAL INSTRUCTION: REALITY CHECK & HALLUCINATION PREVENTION**
    1.  **VERIFY EXISTENCE**: First, use the Google Search tool to confirm this specific business name exists at the provided location. Look for a Google Maps listing, Yelp page, or Official Website.
    2.  **IF NOT FOUND ("Ghost Business")**:
        - If you cannot find a confirmed digital footprint for "${business.name}" in "${business.location}", you **MUST** trigger "Ghost Mode".
        - **Overall Score**: MUST be between 0 and 15.
        - **Summary**: Start with "CRITICAL: DIGITAL FOOTPRINT NOT FOUND." Explain that because the business lacks a verified listing, it is completely invisible to AI models.
        - **Attributes**: Set 'Authority', 'Consistency', and 'Citations' scores to < 10. Label them "Non-Existent".
        - **Visual Audit**: Return score: 0, overallVibe: "Invisible - No Data Found", detectedTags: [].
        - **Do NOT hallucinate** positive traits for a business you cannot find.
    3.  **IF FOUND**: Proceed with the detailed audit below using actual data found in search snippets.

    Task: Simulate an advanced SEO audit for AI engines.

    1.  **Research**: Use Google Search to find real info, reviews, citations, and competitors.
    2.  **LLM Ranking**: Simulate how this business appears specifically in ChatGPT, Gemini, and Perplexity.
    3.  **Local Map**: Identify 10-15 key competitors.
    4.  **KPI Analysis**: For Authority, Consistency, Sentiment, Relevance, and Citations, provide a score (0-100), a label, explanation, and fix.
    5.  **Keyword Heist**: Identify adjectives AI associates with competitors but not the user.
    6.  **Training Data Audit**: Scan for negative words in reviews that might poison AI answers.
    7.  **Daily Missions**: Create 4 specific, actionable tasks.
    8.  **Content Studio Strategy**: Create 3 completely written social media posts (Instagram, LinkedIn, GMB) using *missing* keywords.
    9.  **Voice Search Simulation**: Script what Siri/Google Assistant would say.
    10. **Visual Audit**: 
        - Check if 'images' were provided in this request. 
        - **If YES (Manual Upload):** Analyze them using your vision capabilities. Set 'source' to "Upload".
        - **If NO (Auto Scan):** Use the **Google Search Tool** to find the business's Google Maps listing and look for photos. 
          - *Constraint*: If the business was not found in step 1, return score 0 and state "No visual data found". 
          - If found, analyze the visual style, cleanliness, and vibe. Set 'source' to "GMB_Scan".
        - **Requirement:** You MUST return a 'visualAudit' object in ALL cases.
    11. **Hallucination Monitor (Fact Check)**: Simulate 3-5 specific factual questions (e.g., "Do they have parking?", "Are they dog friendly?", "Do they take reservations?") and provide what the AI *thinks* is the answer based on training data.
    12. **PAA Hijacker**: Generate 3 high-intent "People Also Ask" questions for Voice Search and provide the exact "Position Zero" 40-word answer to paste on their website.

    Return strict JSON.
  `;

  const parts: any[] = [{ text: promptText }];

  // Add images to the payload if they exist
  if (business.images && business.images.length > 0) {
    business.images.forEach(base64Str => {
      // Remove header if present (e.g., "data:image/jpeg;base64,")
      const base64Data = base64Str.split(',')[1];
      parts.push({
        inlineData: {
          mimeType: 'image/jpeg', // Assuming jpeg for simplicity, or detect from header
          data: base64Data
        }
      });
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: parts },
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            overallScore: { type: Type.NUMBER },
            summary: { type: Type.STRING },
            attributes: {
              type: Type.OBJECT,
              properties: {
                authority: { 
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.NUMBER },
                        label: { type: Type.STRING },
                        explanation: { type: Type.STRING },
                        action: { type: Type.STRING }
                    },
                    required: ["score", "label", "explanation", "action"]
                },
                consistency: { 
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.NUMBER },
                        label: { type: Type.STRING },
                        explanation: { type: Type.STRING },
                        action: { type: Type.STRING }
                    },
                    required: ["score", "label", "explanation", "action"]
                },
                sentiment: { 
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.NUMBER },
                        label: { type: Type.STRING },
                        explanation: { type: Type.STRING },
                        action: { type: Type.STRING }
                    },
                    required: ["score", "label", "explanation", "action"]
                },
                relevance: { 
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.NUMBER },
                        label: { type: Type.STRING },
                        explanation: { type: Type.STRING },
                        action: { type: Type.STRING }
                    },
                    required: ["score", "label", "explanation", "action"]
                },
                citations: { 
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.NUMBER },
                        label: { type: Type.STRING },
                        explanation: { type: Type.STRING },
                        action: { type: Type.STRING }
                    },
                    required: ["score", "label", "explanation", "action"]
                },
              },
              required: ["authority", "consistency", "sentiment", "relevance", "citations"]
            },
            simulations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  query: { type: Type.STRING },
                  aiResponse: { type: Type.STRING },
                  rank: { type: Type.STRING, enum: ["Top Recommendation", "Mentioned", "Not Found"] }
                }
              }
            },
            personas: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  personaName: { type: Type.STRING },
                  userIntent: { type: Type.STRING },
                  simulatedQuery: { type: Type.STRING },
                  aiResponseSummary: { type: Type.STRING },
                  brandMentioned: { type: Type.BOOLEAN }
                }
              }
            },
            contentGaps: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  missingElement: { type: Type.STRING },
                  importance: { type: Type.STRING, enum: [ImpactLevel.HIGH, ImpactLevel.MEDIUM, ImpactLevel.LOW] },
                  fix: { type: Type.STRING }
                }
              }
            },
            platformPerformance: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  platform: { type: Type.STRING, enum: ["Chat Interfaces", "Voice Search", "Traditional Search"] },
                  score: { type: Type.NUMBER },
                  status: { type: Type.STRING, enum: ["Optimized", "Needs Work", "Invisible"] }
                }
              }
            },
            llmPerformance: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  model: { type: Type.STRING, enum: ["ChatGPT", "Gemini", "Perplexity"] },
                  status: { type: Type.STRING, enum: ["Top Choice", "Option", "Hidden"] },
                  details: { type: Type.STRING },
                  score: { type: Type.NUMBER }
                }
              }
            },
            localCompetitors: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  rank: { type: Type.NUMBER },
                  distance: { type: Type.STRING },
                  x: { type: Type.NUMBER },
                  y: { type: Type.NUMBER }
                }
              }
            },
            citationOpportunities: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  siteName: { type: Type.STRING },
                  domain: { type: Type.STRING },
                  type: { type: Type.STRING, enum: ["Directory", "Social", "Forum", "Health/Niche"] },
                  priority: { type: Type.STRING, enum: [ImpactLevel.HIGH, ImpactLevel.MEDIUM, ImpactLevel.LOW] },
                  reason: { type: Type.STRING }
                }
              }
            },
            keywordHeist: {
              type: Type.ARRAY,
              items: {
                 type: Type.OBJECT,
                 properties: {
                    term: { type: Type.STRING },
                    owner: { type: Type.STRING, enum: ['Competitor', 'You', 'Shared'] },
                    searchVolume: { type: Type.STRING, enum: ['High', 'Medium', 'Low'] },
                    opportunityScore: { type: Type.NUMBER }
                 }
              }
            },
            sentimentAudit: {
                type: Type.OBJECT,
                properties: {
                    toxicityScore: { type: Type.NUMBER },
                    summary: { type: Type.STRING },
                    negativeEntities: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                term: { type: Type.STRING },
                                frequency: { type: Type.STRING },
                                impact: { type: Type.STRING, enum: ['Critical', 'Moderate', 'Low'] }
                            }
                        }
                    }
                },
                required: ['toxicityScore', 'summary', 'negativeEntities']
            },
            dailyMissions: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        id: { type: Type.STRING },
                        title: { type: Type.STRING },
                        description: { type: Type.STRING },
                        xp: { type: Type.NUMBER },
                        category: { type: Type.STRING, enum: ['Content', 'Review', 'Social'] },
                        estimatedTime: { type: Type.STRING }
                    }
                }
            },
            contentStrategy: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        platform: { type: Type.STRING, enum: ['Instagram', 'LinkedIn', 'GMB'] },
                        focusKeyword: { type: Type.STRING },
                        caption: { type: Type.STRING },
                        hashtags: { type: Type.ARRAY, items: { type: Type.STRING } },
                        imageIdea: { type: Type.STRING },
                        whyThisWorks: { type: Type.STRING }
                    }
                }
            },
            voiceSimulation: {
                type: Type.OBJECT,
                properties: {
                    query: { type: Type.STRING },
                    script: { type: Type.STRING },
                    voiceParams: {
                        type: Type.OBJECT,
                        properties: {
                            pitch: { type: Type.NUMBER },
                            rate: { type: Type.NUMBER }
                        }
                    }
                },
                required: ['query', 'script']
            },
            visualAudit: {
                type: Type.OBJECT,
                properties: {
                    overallVibe: { type: Type.STRING },
                    score: { type: Type.NUMBER },
                    detectedTags: { type: Type.ARRAY, items: { type: Type.STRING } },
                    improvements: { type: Type.STRING },
                    source: { type: Type.STRING, enum: ["Upload", "GMB_Scan"] }
                },
                required: ['overallVibe', 'score', 'detectedTags', 'improvements', 'source']
            },
            factCheck: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        question: { type: Type.STRING },
                        aiAnswer: { type: Type.STRING },
                        confidence: { type: Type.STRING }
                    }
                }
            },
            voiceSearchQA: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        question: { type: Type.STRING },
                        answer: { type: Type.STRING },
                        intent: { type: Type.STRING }
                    }
                }
            },
            competitors: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  strengths: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
              }
            },
            recommendations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING },
                  impact: { type: Type.STRING, enum: [ImpactLevel.HIGH, ImpactLevel.MEDIUM, ImpactLevel.LOW] },
                  actionItem: { type: Type.STRING }
                }
              }
            }
          },
          required: ["overallScore", "summary", "attributes", "simulations", "personas", "contentGaps", "platformPerformance", "llmPerformance", "localCompetitors", "citationOpportunities", "keywordHeist", "sentimentAudit", "dailyMissions", "contentStrategy", "voiceSimulation", "competitors", "recommendations", "visualAudit"]
        }
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("No response from AI");
    }

    const data = JSON.parse(text) as AnalysisResult;
    // Generate simple IDs for missions if not present
    if (data.dailyMissions) {
        data.dailyMissions = data.dailyMissions.map((m, i) => ({
            ...m,
            id: m.id || `mission-${i}`
        }));
    }
    return data;

  } catch (error) {
    console.error("Error analyzing business:", error);
    throw error;
  }
};

export interface BusinessInfo {
  name: string;
  location: string;
  category: string;
  website?: string;
  keywords?: string;
  images?: string[]; // Array of Base64 strings
}

export interface Simulation {
  query: string;
  aiResponse: string;
  rank: 'Top Recommendation' | 'Mentioned' | 'Not Found';
}

export enum ImpactLevel {
  HIGH = 'High',
  MEDIUM = 'Medium',
  LOW = 'Low'
}

export interface Recommendation {
  title: string;
  description: string;
  impact: ImpactLevel;
  actionItem: string;
}

export interface Competitor {
  name: string;
  strengths: string[];
}

export interface PersonaSimulation {
  personaName: string;
  userIntent: string;
  simulatedQuery: string;
  aiResponseSummary: string;
  brandMentioned: boolean;
}

export interface ContentGap {
  missingElement: string;
  importance: ImpactLevel;
  fix: string;
}

export interface PlatformPerformance {
  platform: 'Chat Interfaces' | 'Voice Search' | 'Traditional Search';
  score: number;
  status: 'Optimized' | 'Needs Work' | 'Invisible';
}

// New Types
export interface LLMPerformance {
  model: 'ChatGPT' | 'Gemini' | 'Perplexity';
  status: 'Top Choice' | 'Option' | 'Hidden';
  details: string;
  score: number; // 0-100 visibility score
}

export interface CitationOpportunity {
  siteName: string;
  domain: string;
  type: 'Directory' | 'Social' | 'Forum' | 'Health/Niche';
  priority: ImpactLevel;
  reason: string;
}

export interface LocalCompetitorLocation {
  name: string;
  rank: number;
  distance: string; // e.g., "0.5 miles"
  x: number; // Relative coordinate for map visualization (-10 to 10)
  y: number; // Relative coordinate for map visualization (-10 to 10)
}

// Feature 3: Keyword Heist
export interface KeywordGap {
  term: string;
  owner: 'Competitor' | 'You' | 'Shared';
  searchVolume: 'High' | 'Medium' | 'Low';
  opportunityScore: number; // 0-100
}

// Feature 5: Sentiment Audit
export interface NegativeEntity {
  term: string; // e.g. "Rude", "Slow", "Expensive"
  frequency: string; // e.g. "14% of reviews"
  impact: 'Critical' | 'Moderate' | 'Low';
}

// New Rich Attribute Interface for clearer KPIs
export interface AttributeDetail {
  score: number;
  label: string; // e.g. "Excellent", "Needs Work"
  explanation: string; // Simple English explanation
  action: string; // Immediate next step
}

// Recurring Usage Feature: Daily Missions
export interface DailyMission {
  id: string;
  title: string;
  description: string;
  xp: number; // Gamification points 10-50
  category: 'Content' | 'Review' | 'Social';
  estimatedTime: string; // e.g. "2 mins"
}

// New Feature: AI Content Studio
export interface SocialPostIdea {
  platform: 'Instagram' | 'LinkedIn' | 'GMB';
  focusKeyword: string;
  caption: string;
  hashtags: string[];
  imageIdea: string;
  whyThisWorks: string; // Connects back to the audit gap
}

// New Feature: Voice Simulator
export interface VoiceSimulation {
  query: string;
  script: string; // What the AI "Says"
  voiceParams: {
    pitch: number;
    rate: number;
  };
}

// Feature: Visual GEO Audit
export interface VisualAnalysis {
  overallVibe: string;
  score: number;
  detectedTags: string[];
  improvements: string;
  source: 'Upload' | 'GMB_Scan' | 'Not_Found'; // Added Not_Found
}

// Feature: Hallucination Monitor
export interface FactCheckItem {
  question: string; // e.g., "Is there parking?"
  aiAnswer: string; // "Yes, free parking available."
  confidence: string; // "High" | "Low"
}

// Feature: PAA Hijacker
export interface VoiceQAPair {
  question: string; // "Who has the best gluten free pizza?"
  answer: string; // The perfect 40-word answer to paste
  intent: string; // "Discovery" or "Transactional"
}

export interface AnalysisResult {
  overallScore: number;
  summary: string;
  attributes: {
    authority: AttributeDetail;
    consistency: AttributeDetail;
    sentiment: AttributeDetail;
    relevance: AttributeDetail;
    citations: AttributeDetail;
  };
  simulations: Simulation[];
  personas: PersonaSimulation[];
  contentGaps: ContentGap[];
  platformPerformance: PlatformPerformance[];

  // New Fields
  llmPerformance: LLMPerformance[];
  citationOpportunities: CitationOpportunity[];
  localCompetitors: LocalCompetitorLocation[];

  // High Value Features
  keywordHeist: KeywordGap[];
  sentimentAudit: {
    toxicityScore: number; // 0-100 (0 is clean, 100 is toxic)
    negativeEntities: NegativeEntity[];
    summary: string;
  };

  // Recurring Usage
  dailyMissions: DailyMission[];

  // SaaS Value Features
  contentStrategy: SocialPostIdea[];
  voiceSimulation: VoiceSimulation;

  // Latest Features
  visualAudit?: VisualAnalysis;
  factCheck?: FactCheckItem[];
  voiceSearchQA?: VoiceQAPair[];

  competitors: Competitor[];
  recommendations: Recommendation[];
}

export interface AnalysisState {
  loading: boolean;
  error: string | null;
  result: AnalysisResult | null;
}

