  const [isSpeaking, setIsSpeaking] = useState(false);
  const synthRef = useRef<SpeechSynthesis | null>(null);

  // Map state
  const [hoveredCompetitor, setHoveredCompetitor] = useState<any | null>(null);

  useEffect(() => {
    if (typeof window !== 'undefined') {
