import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, BusinessInfo, ImpactLevel } from "../types";

const getApiKey = (): string => {
  const key = process.env.API_KEY;
  if (!key) {
    throw new Error("API Key not found. Please set REACT_APP_GEMINI_API_KEY.");
  }
  return key;
};

// New function to fetch REAL ChatGPT data if key exists
const fetchChatGPTInsight = async (business: BusinessInfo, openaiKey: string): Promise<string> => {
    try {
        const response = await fetch("https://api.openai.com/v1/chat/completions", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
                "Authorization": `Bearer ${openaiKey}`
            },
            body: JSON.stringify({
                model: "gpt-4o-mini", // Use mini for speed and cost
                messages: [
                    {
                        role: "system",
                        content: "You are a helpful local guide. Answer concisely."
                    },
                    {
                        role: "user",
                        content: `I am looking for the best ${business.category} in ${business.location}. Please provide your top 3 recommendations and explain why. Also, do you know "${business.name}"? If so, what is your opinion on it?`
                    }
                ],
                max_tokens: 300
            })
        });

        if (!response.ok) return "Error fetching ChatGPT data.";
        const data = await response.json();
        return data.choices?.[0]?.message?.content || "No response from ChatGPT.";
    } catch (e) {
        console.error("OpenAI Fetch Error", e);
        return "Failed to connect to OpenAI.";
    }
};

export const analyzeBusinessVisibility = async (business: BusinessInfo, openaiKey?: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: getApiKey() });

  // 1. Fetch Real ChatGPT Data (Parallel)
  let realChatGPTData = "Simulation Mode (No Key Provided)";
  if (openaiKey) {
      realChatGPTData = await fetchChatGPTInsight(business, openaiKey);
  }

  const promptText = `
    Analyze the "LLM Visibility" (GEO - Generative Engine Optimization) for:

    Business Input: ${business.name}
    Location: ${business.location}
    Category: ${business.category}
    ${business.website ? `Website: ${business.website}` : ''}

    **HYBRID AUDIT CONTEXT (REAL DATA INJECTION)**
    Real ChatGPT Response to "Best ${business.category} in ${business.location}": 
    "${realChatGPTData}"

    ========================================================
    PHASE 1: SMART DISCOVERY & VERIFICATION (CRITICAL FIX)
    ========================================================
    Your first task is to find this business. Do NOT be lazy. 
    Users often enter simplified names (e.g., "Harmony Health") while the real listing is formal (e.g., "Cabinet de Kinésithérapie Harmony").

    **SEARCH STRATEGY:**
    1.  **Direct Search**: Search for "${business.name} ${business.location}".
    2.  **Category Search**: Search for "${business.category} in ${business.location}" and look for the name in the results.
    3.  **Local Language Search**: If the location is non-English (e.g., Morocco, Spain, France), YOU MUST search using local terms (e.g., "Kiné ${business.name} Tanger", "Physiotherapy ${business.name}").

    **MATCHING PROTOCOL (FUZZY MATCHING ALLOWED):**
    - If you find a business with a **similar name** in the **same city** that matches the **category**, **ACCEPT IT** as the business.
    - **Do NOT trigger Ghost Mode** simply because the name isn't an exact string match.
    - Example: User inputs "Harmony Health". You find "Cabinet Harmony Tangier". -> **MATCH FOUND**. Proceed with audit.

    **GHOST MODE (LAST RESORT):**
    - Only trigger "Ghost Mode" (Score < 15) if you are 100% certain NO listing exists after trying English, French, and local variations.

    ========================================================
    PHASE 2: THE AUDIT (If Found)
    ========================================================
    Target Audience: Business owner (Non-technical). Use simple, actionable language.

    1.  **LLM Ranking**: 
        - **ChatGPT**: Analyze the "Real ChatGPT Response" provided above. If it mentions the business, rank "Top Choice" or "Option". If not, "Hidden".
        - **Gemini**: Simulate based on your Google Search findings.
        - **Perplexity**: Simulate based on web citations found.
    2.  **Local Map**: Identify 10-15 real competitors. Provide approx Lat/Lng.
    3.  **Market Intelligence (Ecosystem View)**:
        - Analyze the ${business.category} market in ${business.location} as a WHOLE.
        - **Popular Prompts**: What are the 3 most common questions users ask AI about this specific category in this city? (e.g. "Cheap dentist Tangier", "English speaking lawyer Madrid").
        - **Competition Level**: Is it Blue Ocean (Empty) or Cut-throat?
        - **Opportunity Niche**: What is one thing NO ONE in this area is doing well? (e.g. "No one has online booking").
        - **Hidden Factor**: A secret ranking factor specific to this city (e.g. "In this city, parking mentions are critical").
    4.  **KPI Analysis**:
        - **Authority**: Does the business appear in "Best of" lists or high-authority directories?
        - **Consistency**: Is the NAP (Name, Address, Phone) consistent across Google, Facebook, etc.?
        - **Sentiment**: Read 5-10 reviews. Score based on tone.
    5.  **Citation Analysis (The "Data Supply Chain")**:
        - **CRITICAL ACCURACY STEP**: Do not guess. Simulate a search for "Best ${business.category} in ${business.location}".
        - Identify the **directories/aggregators** that rank on Google Page 1 (e.g., TripAdvisor, Yelp, Doctolib, Treatwell, YellowPages, Reddit).
        - **Logic**: Gemini uses Google Search results as its primary RAG source. If a directory is on Page 1, Gemini reads it. If it's on Page 10, Gemini ignores it.
        - **Competitor Check**: Look at the top 3 competitors found. Where are *they* listed that this business is not?
        - Return 5 specific opportunities.
        - For each, populate 'feedsModels' with who uses it (e.g., "Google Maps" -> ["Gemini"], "Yelp" -> ["ChatGPT", "Apple"], "TripAdvisor" -> ["ChatGPT", "Perplexity"]).
    6.  **Keyword Heist**: Find adjectives used in competitor reviews (e.g., "Professional", "Clean", "Modern") that are missing from the user's profile.
    7.  **Visual Audit**:
        - If 'images' provided: Analyze them.
        - If NO 'images': Use Google Search to find the GMB Listing photos. 
        - **CRITICAL FIX**: If you found the business listing in Phase 1, but cannot "see" the photos, assume "Average" vibe but do NOT fail the audit. Mark source as "GMB_Scan".
        - Only return "Not_Found" if Phase 1 failed completely.

    Return strict JSON.
  `;

  const parts: any[] = [{ text: promptText }];

  // Add images to the payload if they exist
  if (business.images && business.images.length > 0) {
    business.images.forEach(base64Str => {
      // Remove header if present (e.g., "data:image/jpeg;base64,")
      const base64Data = base64Str.split(',')[1];
      parts.push({
        inlineData: {
          mimeType: 'image/jpeg', // Assuming jpeg for simplicity, or detect from header
          data: base64Data
        }
      });
    });
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: parts },
      config: {
        tools: [{ googleSearch: {} }],
        // STABILITY SETTINGS: Low temperature for consistent scoring
        temperature: 0.1,
        topK: 40,
        topP: 0.95,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            overallScore: { type: Type.NUMBER },
            summary: { type: Type.STRING },
            businessCoordinates: {
                type: Type.OBJECT,
                properties: {
                    lat: { type: Type.NUMBER },
                    lng: { type: Type.NUMBER }
                },
                required: ["lat", "lng"]
            },
            marketOverview: {
                type: Type.OBJECT,
                properties: {
                    marketVibe: { type: Type.STRING },
                    competitionLevel: { type: Type.STRING, enum: ['Cut-throat', 'Moderate', 'Low', 'Blue Ocean'] },
                    popularPrompts: { type: Type.ARRAY, items: { type: Type.STRING } },
                    opportunityNiche: { type: Type.STRING },
                    hiddenRankingFactor: { type: Type.STRING }
                },
                required: ['marketVibe', 'competitionLevel', 'popularPrompts', 'opportunityNiche', 'hiddenRankingFactor']
            },
            attributes: {
              type: Type.OBJECT,
              properties: {
                authority: { 
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.NUMBER },
                        label: { type: Type.STRING },
                        explanation: { type: Type.STRING },
                        action: { type: Type.STRING }
                    },
                    required: ["score", "label", "explanation", "action"]
                },
                consistency: { 
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.NUMBER },
                        label: { type: Type.STRING },
                        explanation: { type: Type.STRING },
                        action: { type: Type.STRING }
                    },
                    required: ["score", "label", "explanation", "action"]
                },
                sentiment: { 
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.NUMBER },
                        label: { type: Type.STRING },
                        explanation: { type: Type.STRING },
                        action: { type: Type.STRING }
                    },
                    required: ["score", "label", "explanation", "action"]
                },
                relevance: { 
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.NUMBER },
                        label: { type: Type.STRING },
                        explanation: { type: Type.STRING },
                        action: { type: Type.STRING }
                    },
                    required: ["score", "label", "explanation", "action"]
                },
                citations: { 
                    type: Type.OBJECT,
                    properties: {
                        score: { type: Type.NUMBER },
                        label: { type: Type.STRING },
                        explanation: { type: Type.STRING },
                        action: { type: Type.STRING }
                    },
                    required: ["score", "label", "explanation", "action"]
                },
              },
              required: ["authority", "consistency", "sentiment", "relevance", "citations"]
            },
            simulations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
